INSERT INTO `security_rules` (`id`, `provider`, `service`, `check_id`, `title`, `description`, `severidad_id`, `condition_logic`, `remediation`, `reference`, `creacion`, `actualizacion`, `display_name`, `estado_id`) VALUES
(67, 'aws', 's3', 'lifecycle_enabled', 'S3 Bucket Lifecycle Policy Not Configured', 'El bucket de Amazon S3 no tiene configurada una política de ciclo de vida (Lifecycle Policy). Las políticas de ciclo de vida permiten automatizar la transición de objetos entre clases de almacenamiento y la expiración de datos obsoletos, optimizando costos y reduciendo la superficie de exposición de datos innecesarios.', 2, 'Se verifica que el bucket no tenga configurada ninguna regla de ciclo de vida activa mediante la API get_bucket_lifecycle_configuration. Si la respuesta retorna NoSuchLifecycleConfiguration o el array de reglas está vacío, el check falla.', 'Configurar una política de ciclo de vida en el bucket S3 según la naturaleza de los datos almacenados. Se recomienda definir reglas que transicionen objetos a clases de menor costo (S3-IA, Glacier) luego de un período definido, y que expiren objetos obsoletos automáticamente. Acceder desde AWS Console → S3 → Bucket → Management → Lifecycle rules.', 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/object-lifecycle-mgmt.html', '2026-05-05 17:57:23', '2026-05-05 17:57:23', NULL, 1),
(68, 'aws', 's3', 'dangerous_write_permissions', 'S3 Bucket Dangerous Write Permissions Detected', 'El bucket de Amazon S3 tiene configurada una política IAM que otorga permisos de escritura peligrosos (s3:PutObject, s3:DeleteObject, s3:PutBucketPolicy, s3:PutObjectAcl o s3:*) a uno o más principales. Esto puede permitir que entidades no autorizadas modifiquen, eliminen o reemplacen objetos y políticas del bucket, comprometiendo la integridad y confidencialidad de los datos almacenados.', 4, 'Se analiza la política de bucket mediante get_bucket_policy. Para cada statement con Effect: Allow, se verifican las acciones permitidas. Si alguna acción coincide con el conjunto de permisos peligrosos (s3:PutObject, s3:DeleteObject, s3:PutBucketPolicy, s3:PutObjectAcl, s3:*), el check falla.', 'Revisar y restringir las políticas IAM del bucket aplicando el principio de mínimo privilegio. Eliminar o acotar los permisos de escritura innecesarios. Si el acceso de escritura es requerido, limitarlo a principals específicos mediante condiciones como aws:PrincipalArn o aws:SourceAccount. Considerar el uso de S3 Object Lock para proteger objetos críticos contra modificaciones o eliminaciones.', 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-overview.html', '2026-05-05 22:52:59', '2026-05-05 22:52:59', NULL, 1),
(69, 'aws', 's3', 'wildcard_resource', 'S3 Bucket Policy Contains Wildcard Resource', 'La política IAM del bucket de Amazon S3 contiene una o más sentencias con Resource: \"*\" o Resource: \"arn:aws:s3:::bucket/*\" que aplican permisos sobre todos los objetos sin restricción de prefijo o path específico. El uso de recursos comodín amplía innecesariamente el alcance de los permisos otorgados, aumentando la superficie de ataque y el riesgo de acceso no autorizado a datos sensibles.', 4, '\nSe analiza la política de bucket mediante get_bucket_policy. Para cada statement con Effect: Allow, se evalúa el campo Resource. Si algún valor es \"*\" o termina en \"/*\" abarcando la totalidad de los objetos del bucket sin restricción de prefijo, el check falla.', 'Reemplazar los recursos comodín por ARNs específicos que limiten el acceso a los prefijos o paths estrictamente necesarios. Por ejemplo, en lugar de arn:aws:s3:::mi-bucket/* utilizar arn:aws:s3:::mi-bucket/carpeta-especifica/*. Revisar periódicamente las políticas de bucket para asegurar que los recursos referenciados sean los mínimos necesarios para cada caso de uso.', 'https://docs.aws.amazon.com/IAM/latest/UserGuide/reference_policies_elements_resource.html', '2026-05-05 22:54:27', '2026-05-05 22:54:27', NULL, 1),
(70, 'aws', 'lambda', 'env_secret_exposed', 'Lambda Environment Variable Contains Potential Secret', 'La función Lambda tiene configuradas variables de entorno cuyo nombre o valor sugieren que contienen información sensible como credenciales, tokens, claves de API o secretos. El almacenamiento de secretos en variables de entorno en texto plano representa un riesgo de exposición ya que cualquier entidad con acceso a la configuración de la función puede leerlos directamente desde la consola AWS, la CLI o la API. Adicionalmente, los secretos en variables de entorno pueden quedar expuestos en logs, trazas o snapshots no controlados.', 5, 'Se analizan las variables de entorno de cada función Lambda mediante get_function_configuration. El check falla cuando el nombre de la variable contiene palabras clave sospechosas (password, secret, token, apikey, api_key, access_key, private_key, jwt, db_, database) o cuando el valor tiene más de 30 caracteres con una combinación de letras y números que sugiere alta entropía.', 'Migrar todos los secretos y credenciales almacenados en variables de entorno a AWS Secrets Manager o AWS Systems Manager Parameter Store (con cifrado KMS). Actualizar el código de la función para que recupere los secretos en tiempo de ejecución mediante las APIs correspondientes. Rotar inmediatamente cualquier credencial que haya estado expuesta como variable de entorno. Revisar los permisos IAM del rol de ejecución para asegurar acceso mínimo a Secrets Manager.', 'https://docs.aws.amazon.com/secretsmanager/latest/userguide/intro.html', '2026-05-05 22:56:14', '2026-06-16 12:52:26', NULL, 1),
(71, 'aws', 'vpc', 'open_ingress_sensitive_ports', 'Security Group Allows Unrestricted Ingress on Sensitive Ports', 'El Security Group permite tráfico entrante desde 0.0.0.0/0 en puertos administrativos o de base de datos (22, 3389, 3306, 5432, 1433, 6379).', 4, 'Se analizan las reglas inbound de cada Security Group mediante describe_security_groups, identificando rangos CIDR 0.0.0.0/0 o ::/0 combinados con puertos sensibles.', 'Restringir el origen del tráfico a rangos de IP específicos o utilizar un bastion host / VPN para acceso administrativo.', 'https://docs.aws.amazon.com/vpc/latest/userguide/security-group-rules.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(72, 'aws', 'vpc', 'unrestricted_egress_all_ports', 'Security Group Allows Unrestricted Egress', 'El Security Group permite tráfico saliente sin restricción hacia 0.0.0.0/0 en todos los puertos, facilitando exfiltración o comunicación C2 desde una instancia comprometida.', 3, 'Se revisan las reglas outbound de cada Security Group buscando reglas ALLOW ALL hacia 0.0.0.0/0 sin restricción de puerto o protocolo.', 'Limitar el tráfico saliente a los destinos y puertos estrictamente necesarios para la operación del recurso.', 'https://docs.aws.amazon.com/vpc/latest/userguide/security-group-rules.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(73, 'aws', 'vpc', 'subnet_auto_assign_public_ip', 'Subnet Auto-Assigns Public IP Addresses', 'La subnet tiene habilitado MapPublicIpOnLaunch, asignando IP pública automáticamente a cualquier instancia lanzada, incluso sin intención explícita de exponerla.', 2, 'Se consulta describe_subnets verificando el atributo MapPublicIpOnLaunch en cada subnet de la VPC.', 'Deshabilitar la asignación automática de IP pública y usar Elastic IP o NAT Gateway de forma explícita cuando se requiera salida a Internet.', 'https://docs.aws.amazon.com/vpc/latest/userguide/configure-subnets.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(74, 'aws', 'vpc', 'flow_logs_disabled', 'VPC Flow Logs Not Enabled', 'La VPC no tiene Flow Logs habilitados, eliminando visibilidad sobre tráfico este-oeste y norte-sur necesaria para detección de movimiento lateral o exfiltración.', 2, 'Se consulta describe_flow_logs filtrando por resource-id de la VPC; ausencia de resultados indica que no hay logging configurado.', 'Habilitar VPC Flow Logs hacia CloudWatch Logs o S3 con retención adecuada para análisis forense.', 'https://docs.aws.amazon.com/vpc/latest/userguide/flow-logs.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(75, 'aws', 'vpc', 'default_vpc_active', 'Default VPC In Use Without Hardening', 'La VPC default de la región está activa con su configuración original (subnets públicas en todas las AZs, Security Group default permisivo), rara vez auditada pero presente en la mayoría de las cuentas.', 1, 'Se identifica la VPC con el atributo isDefault=true mediante describe_vpcs y se valida si sigue en uso o sin restricciones aplicadas.', 'Evaluar la eliminación de la VPC default o aplicar el mismo nivel de hardening que a las VPCs productivas (SGs, NACLs, subnets privadas).', 'https://docs.aws.amazon.com/vpc/latest/userguide/default-vpc.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(76, 'aws', 'vpc', 'nacl_allow_all', 'Network ACL Permits All Traffic', 'La Network ACL asociada permite todo el tráfico entrante/saliente (regla equivalente a ALLOW ALL), anulando el efecto de los Security Groups configurados correctamente.', 2, 'Se analizan las reglas de describe_network_acls buscando entradas con CidrBlock 0.0.0.0/0, Protocol -1 y RuleAction allow en una posición de prioridad baja.', 'Definir reglas explícitas de NACL alineadas al principio de menor privilegio, evitando reglas ALLOW ALL genéricas.', 'https://docs.aws.amazon.com/vpc/latest/userguide/vpc-network-acls.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(77, 'aws', 'vpc', 'peering_unrestricted_cidr', 'VPC Peering Route Exposes Full CIDR Range', 'La tabla de rutas de un peering expone el rango CIDR completo de la VPC remota sin restricción granular, habilitando pivoting no documentado entre entornos (ej. dev → prod).', 3, 'Se revisan describe_route_tables y describe_vpc_peering_connections correlacionando rutas con destino pcx-* contra el CIDR completo de la VPC remota.', 'Segmentar las rutas de peering a subredes específicas en lugar del CIDR completo, y aplicar Security Groups adicionales en el límite del peering.', 'https://docs.aws.amazon.com/vpc/latest/peering/peering-configurations.html', '2026-06-16 10:34:38', '2026-06-16 10:34:38', NULL, 1),
(78, 'aws', 's3', 'public_via_policy', 'S3 Bucket Publicly Accessible via Bucket Policy', 'La política del bucket de Amazon S3 contiene una o más declaraciones que otorgan acceso público (Principal: \"*\" o {\"AWS\": \"*\"} con Effect: Allow) sin condiciones que restrinjan el origen o la identidad del solicitante. Esto permite que cualquier usuario de Internet, autenticado o no, pueda ejecutar las acciones permitidas por la política (lectura, escritura u otras) sobre los objetos del bucket, exponiendo su contenido sin control de acceso real.', 5, 'Se analiza la política del bucket mediante get_bucket_policy. Para cada statement con Effect: Allow, se evalúa si el campo Principal es \"*\" o {\"AWS\": \"*\"} sin una cláusula Condition que restrinja el acceso (por ejemplo aws:SourceVpc, aws:SourceIp, aws:PrincipalOrgID, aws:Referer). Si existe al menos un statement que cumpla esta condición sin restricción asociada, el check falla.', 'Eliminar o modificar las declaraciones de política que otorgan acceso público sin restricciones. Si el bucket requiere acceso público legítimo (por ejemplo, hosting de sitio web estático), limitar el acceso mediante condiciones específicas (aws:SourceIp, aws:Referer) o aislar ese contenido en un bucket dedicado. Habilitar S3 Block Public Access a nivel de cuenta y de bucket para prevenir que se reintroduzcan políticas públicas en el futuro.', 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-policy-language-overview.html', '2026-06-16 20:50:09', '2026-06-16 20:50:09', NULL, 1),
(79, 'aws', 's3', 'block_public_access_disabled', 'S3 Block Public Access Disabled', 'El bucket de Amazon S3 (o la cuenta en su totalidad) no tiene habilitadas las configuraciones de Block Public Access (BlockPublicAcls, IgnorePublicAcls, BlockPublicPolicy, RestrictPublicBuckets). Esta es la última capa de protección de AWS contra exposición pública accidental: aunque no exista hoy una ACL o política pública activa, su ausencia permite que una futura mala configuración (manual o automatizada) deje el bucket expuesto sin ningún control que lo bloquee.', 3, 'Se consulta la configuración de Block Public Access del bucket mediante get_public_access_block (y opcionalmente a nivel de cuenta). Si alguna de las cuatro banderas (BlockPublicAcls, IgnorePublicAcls, BlockPublicPolicy, RestrictPublicBuckets) está en false, o si la configuración no existe (NoSuchPublicAccessBlockConfiguration), el check falla.', 'Habilitar las cuatro configuraciones de Block Public Access tanto a nivel de cuenta como de cada bucket individual, salvo que exista una excepción justificada y documentada (por ejemplo, un bucket de hosting estático que requiera acceso público controlado). Acceder desde AWS Console → S3 → Bucket → Permissions → Block public access, o a nivel de cuenta desde S3 → Block Public Access settings for this account.', 'https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html', '2026-06-16 20:50:58', '2026-06-16 20:50:58', NULL, 1),
(80, 'aws', 's3', 'is_effectively_public', 'S3 Bucket Is Effectively Public', 'AWS determina, mediante su propio análisis combinado de ACLs, política de bucket y configuración de Block Public Access, que el bucket de Amazon S3 es efectivamente público (IsPublic: true). A diferencia de revisar cada control por separado, este veredicto refleja el resultado neto de todas las capas de seguridad evaluadas en conjunto: aunque alguna política o ACL individual pudiera parecer restrictiva, la combinación final de configuraciones deja el bucket accesible desde Internet sin autenticación.', 5, 'Se consulta get_bucket_policy_status, que retorna el campo PolicyStatus.IsPublic calculado por AWS combinando la política del bucket, las ACLs y la configuración de Block Public Access vigente. Si IsPublic retorna true, el check falla, independientemente de que los controles individuales (política, ACL, BPA) parezcan correctos cuando se inspeccionan por separado.', 'Dado que este veredicto es el resultado combinado de múltiples controles, revisar en conjunto: (1) la política del bucket, eliminando declaraciones con Principal público sin restricciones; (2) las ACLs del bucket y sus objetos, removiendo grants hacia AllUsers o AuthenticatedUsers; y (3) habilitar las cuatro configuraciones de Block Public Access. Verificar nuevamente con get_bucket_policy_status tras cada cambio hasta confirmar IsPublic: false.', 'https://docs.aws.amazon.com/AmazonS3/latest/API/API_GetBucketPolicyStatus.html', '2026-06-16 20:51:45', '2026-06-16 20:51:45', NULL, 1);
INSERT INTO `servicios_aws` (`id`, `nombre`, `descripcion`, `tipos_servicio_id`, `creacion`, `actualizacion`, `estado_id`) VALUES
(1, 'S3', 'Auditoría de configuraciones y permisos en buckets S3. Identifica exposición pública, ACL incorrectas y filtración de datos sensibles.', 1, '2026-02-16 23:36:49', NULL, 1),
(2, 'EC2', 'Análisis de instancias y Security Groups en entornos cloud. Detecta puertos expuestos, accesos inseguros y riesgos en metadata service.', 1, '2026-02-16 23:36:49', NULL, 1),
(3, 'IAM', 'Evaluación de políticas, roles y privilegios en la cuenta AWS. Identifica permisos excesivos y posibles escenarios de escalamiento de privilegios.', 1, '2026-02-16 23:36:49', NULL, 1),
(4, 'API Gateway', 'Servicio de exposición y gestión de APIs en AWS.\nPermite auditar endpoints públicos, métodos habilitados, autenticación y configuraciones CORS inseguras.', 1, '2026-02-16 23:36:49', NULL, 1),
(5, 'AWS Lambda', 'Servicio de ejecución serverless que corre código bajo demanda.\nPermite evaluar permisos IAM asociados, exposición de secretos en variables de entorno y riesgos de ejecución no autorizada.Identifica accesibilidad pública, configuraciones débiles y falta de cifrado.', 1, '2026-02-16 23:36:49', NULL, 1),
(6, 'Amazon Inspector', 'Importa y gestiona hallazgos de vulnerabilidades CVE detectados por Amazon Inspector en recursos EC2, Lambda y contenedores.', 1, '2026-05-05 18:22:47', NULL, 1),
(7, 'VPC', 'VPC (Virtual Private Cloud): Audita la configuración de red virtual de AWS (subnets, security groups, rutas) detectando exposición a Internet, reglas de firewall permisivas y falta de segmentación.\nVulnerabilidades conocidas: Security Groups abiertos a 0.0.0.0/0, subnets públicas con recursos sensibles, ausencia de Flow Logs y VPC Peering sin restricción de rutas.', 1, '2026-05-05 18:22:47', NULL, 1),
(8, 'RDS', 'Auditoría de configuraciones y permisos en instancias Amazon RDS, identificando exposición pública, falta de cifrado y debilidades en backups y autenticación.', 1, '2026-06-16 17:01:26', NULL, 1);
INSERT INTO `servicios_aws_acciones` (`id`, `servicios_aws_id`, `accion_key`, `nombre_ui`, `descripcion`, `handler`, `requiere_parametros`, `orden`, `creacion`, `actualizacion`, `estado_id`) VALUES
(1, 3, 'iam.discovery.roles', 'Discovery Roles', 'Lista todos los roles IAM', 'cloud.aws.discovery_roles_job', 0, 1, '2026-02-17 16:56:00', '2026-02-18 20:25:51', 1),
(2, 3, 'iam.discovery.policies', 'Discovery Policies', 'Policies IAM activas (con attachments)', 'cloud.aws.discovery_policies_job', 0, 2, '2026-02-17 16:56:00', '2026-02-20 19:52:17', 1),
(3, 3, 'iam.password_policy', 'Password Policy', 'Obtiene política de password IAM', 'cloud.aws.password_policy_job', 0, 3, '2026-02-17 16:56:00', '2026-02-18 17:01:05', 1),
(4, 1, 's3.discovery.public_exposure', 'S3 Public Exposure', 'Detecta buckets S3 expuestos públicamente debido a configuraciones inseguras en listas de control de acceso (ACL) o políticas de bucket permisivas.', 'cloud.aws.s3_public_exposure_job', 0, 1, '2026-02-18 16:55:04', '2026-02-18 20:30:36', 1),
(5, 1, 's3.discovery.encryption_logging', 'S3 Encryption & Logging', 'Evalúa si los buckets S3 cuentan con cifrado habilitado, versionado activo y registro de accesos (logging) configurado correctamente.', 'cloud.aws.s3_encryption_logging_job', 0, 2, '2026-02-18 16:55:04', '2026-02-18 20:32:10', 1),
(6, 1, 's3.discovery.iam_access_review', 'S3 IAM Access Review', 'Analiza accesos excesivos y permisos IAM sobre buckets S3', 'cloud.aws.s3_iam_access_review_job', 0, 3, '2026-02-18 16:55:04', '2026-02-18 17:01:14', 1),
(7, 2, 'ec2.discovery.security_groups', 'EC2 Security Groups Exposure', 'Detecta reglas inseguras en Security Groups, incluyendo puertos expuestos a 0.0.0.0/0.', 'cloud.aws.ec2_security_groups_job', 0, 1, '2026-02-18 20:38:46', '2026-02-18 20:38:46', 1),
(8, 2, 'ec2.discovery.public_instances', 'EC2 Public Instances', 'Identifica instancias EC2 con IP pública asociada y exposición potencial a internet.', 'cloud.aws.ec2_public_instances_job', 0, 2, '2026-02-18 20:38:46', '2026-02-18 20:38:46', 1),
(9, 2, 'ec2.discovery.iam_roles', 'EC2 IAM Role Review', 'Revisa instancias EC2 con IAM Roles adjuntos para detectar privilegios excesivos.', 'cloud.aws.ec2_iam_role_review_job', 0, 3, '2026-02-18 20:38:46', '2026-02-18 20:38:46', 1),
(10, 4, 'apigateway.discovery.apis', 'Discovery APIs', 'Lista todas las APIs REST y HTTP expuestas en API Gateway', 'cloud.aws.apigateway_public_exposure_job', 0, 1, '2026-02-19 09:39:39', '2026-02-19 10:03:41', 1),
(11, 4, 'apigateway.discovery.stages', 'Discovery Stages', 'Lista stages configurados (dev, prod, test) y sus configuraciones', 'cloud.aws.apigateway_discovery_stages_job', 0, 2, '2026-02-19 09:39:47', '2026-02-19 09:39:47', 1),
(12, 4, 'apigateway.review.authorizers', 'Review Authorizers', 'Analiza configuraciones de autenticación y authorizers (JWT, Cognito, Lambda)', 'cloud.aws.apigateway_review_authorizers_job', 0, 3, '2026-02-19 09:39:55', '2026-02-19 09:39:55', 1),
(13, 4, 'apigateway.security.exposure', 'Security Exposure Review', 'Detecta APIs públicas, CORS abiertos y configuraciones inseguras', 'cloud.aws.apigateway_security_exposure_job', 0, 4, '2026-02-19 09:40:01', '2026-02-19 09:40:01', 1),
(14, 4, 'apigateway.review.logging', 'Logging Review', 'Verifica si CloudWatch logging y execution logs están habilitados', 'cloud.aws.apigateway_logging_review_job', 0, 5, '2026-02-19 09:40:07', '2026-02-19 09:40:07', 1),
(15, 5, 'lambda.discovery.functions', 'Discovery Functions', 'Lista todas las funciones Lambda configuradas en la cuenta', 'cloud.aws.discovery_functions_job', 0, 1, '2026-02-19 12:27:30', '2026-02-19 12:35:26', 1),
(16, 5, 'lambda.discovery.permissions', 'Discovery Permissions', 'Enumera las políticas de recurso asociadas a funciones Lambda', 'cloud.aws.discovery_permissions_job', 0, 2, '2026-02-19 12:27:30', '2026-02-19 12:37:14', 1),
(17, 5, 'lambda.discovery.triggers', 'Discovery Triggers', 'Lista los triggers configurados (API Gateway, S3, EventBridge, etc)', 'cloud.aws.discovery_triggers_job', 0, 3, '2026-02-19 12:27:30', '2026-02-19 12:38:55', 1),
(18, 5, 'lambda.security.public_exposure', 'Public Exposure Check', 'Detecta funciones Lambda expuestas públicamente', 'cloud.aws.public_exposure_review_job', 0, 10, '2026-02-19 12:27:30', '2026-02-19 12:44:11', 1),
(19, 5, 'lambda.security.overprivileged_role', 'Overprivileged Role Check', 'Detecta roles IAM con permisos excesivos asociados a Lambda', 'cloud.aws.overprivileged_role_review_job', 0, 11, '2026-02-19 12:27:30', '2026-02-19 12:45:37', 1),
(20, 5, 'lambda.security.wildcard_permissions', 'Wildcard Permissions Check', 'Detecta uso de * en políticas IAM asociadas a Lambda', 'cloud.aws.wildcard_permissions_review_job', 0, 12, '2026-02-19 12:27:30', '2026-02-19 12:50:42', 1),
(21, 5, 'lambda.security.no_vpc', 'VPC Not Configured', 'Detecta funciones Lambda que no están asociadas a una VPC', 'cloud.aws.no_vpc_review_job', 0, 13, '2026-02-19 12:27:30', '2026-02-19 12:54:07', 1),
(22, 5, 'lambda.security.old_runtime', 'Outdated Runtime Check', 'Detecta funciones usando runtimes obsoletos (versiones de lenguajes ya no soportadas por AWS)', 'cloud.aws.old_runtime_review_job', 0, 14, '2026-02-19 12:27:30', '2026-02-21 00:14:30', 1),
(23, 5, 'lambda.security.env_secrets', 'Environment Secrets Exposure', 'Detecta uso inseguro de secrets en variables de entorno', 'cloud.aws.env_secrets_review_job', 0, 15, '2026-02-19 12:27:30', '2026-02-19 12:58:31', 1),
(24, 5, 'lambda.security.logging_disabled', 'Logging Disabled Check', 'Verifica si la función Lambda no tiene logging activo en CloudWatch', 'cloud.aws.logging_review_job', 0, 16, '2026-02-19 12:27:30', '2026-02-19 13:00:15', 1),
(25, 1, 's3.replication.review', 'S3 Replication Review', 'Verifica si los buckets S3 tienen configurada replicación cross-region', 'cloud.aws.s3_replication_review_job', 0, 4, '2026-04-15 18:27:40', '2026-04-15 18:27:40', 1),
(26, 1, 's3.lifecycle.review', 'S3 Lifecycle Policy Review', 'Verifica si los buckets S3 tienen políticas de ciclo de vida configuradas', 'cloud.aws.s3_lifecycle_review_job', 0, 5, '2026-04-15 18:27:40', '2026-04-15 18:27:40', 1),
(27, 3, 'iam.users.review', 'IAM Users Review', 'Detecta usuarios IAM sin MFA, con acceso a consola sin restricciones o con access keys antiguas', 'cloud.aws.iam_users_review_job', 0, 4, '2026-04-15 18:47:28', '2026-04-15 18:47:28', 1),
(28, 3, 'iam.privilege.escalation', 'IAM Privilege Escalation Review', 'Detecta roles y usuarios con permisos que permiten escalar privilegios en la cuenta AWS', 'cloud.aws.iam_privilege_escalation_job', 0, 5, '2026-04-15 18:47:28', '2026-04-15 18:47:28', 1),
(29, 6, 'inspector.status.check', 'Inspector Status Check', 'Verifica si Amazon Inspector está habilitado en la cuenta y qué tipos de escaneo están activos', 'cloud.aws.inspector_status_job', 0, 1, '2026-05-05 20:01:52', '2026-05-05 20:01:52', 1),
(30, 6, 'inspector.findings.ec2', 'EC2 CVE Findings', 'Importa vulnerabilidades CVE detectadas por Amazon Inspector en instancias EC2', 'cloud.aws.inspector_ec2_findings_job', 0, 2, '2026-05-05 20:01:52', '2026-05-05 20:01:52', 1),
(31, 6, 'inspector.findings.lambda', 'Lambda CVE Findings', 'Importa vulnerabilidades CVE detectadas por Amazon Inspector en funciones Lambda', 'cloud.aws.inspector_lambda_findings_job', 0, 3, '2026-05-05 20:01:52', '2026-05-05 20:01:52', 1),
(32, 6, 'inspector.findings.ecr', 'ECR Image CVE Findings', 'Importa vulnerabilidades CVE detectadas por Amazon Inspector en imágenes de contenedores ECR', 'cloud.aws.inspector_ecr_findings_job', 0, 4, '2026-05-05 20:01:52', '2026-05-05 20:01:52', 1),
(33, 6, 'inspector.findings.critical', 'Critical Findings Review', 'Filtra y lista únicamente los hallazgos CRITICAL detectados por Amazon Inspector en todos los recursos', 'cloud.aws.inspector_critical_findings_job', 0, 5, '2026-05-05 20:02:37', '2026-05-05 20:02:37', 1),
(34, 6, 'inspector.findings.high', 'High Findings Review', 'Filtra y lista únicamente los hallazgos HIGH detectados por Amazon Inspector en todos los recursos', 'cloud.aws.inspector_high_findings_job', 0, 6, '2026-05-05 20:02:37', '2026-05-05 20:02:37', 1),
